const ALL_ITEM_IDS = [];
MCQ.forEach((m,i)=>ALL_ITEM_IDS.push({id:`mcq-${i}`, kind:"mcq", lectio:null, label:m.q.slice(0,42)+"…"}));
MATCH.forEach((set,si)=>set.pairs.forEach((p,pi)=>ALL_ITEM_IDS.push({id:`match-${si}-${pi}`, kind:"match", lectio:null, label:p[0].slice(0,42)+"…"})));
LECTIOS.forEach(l=>{
  l.sentences.forEach((s,i)=>ALL_ITEM_IDS.push({id:`${l.id}-t${i}`, kind:"translate", lectio:l.id, label:s.lat.slice(0,42)+"…"}));
  l.syntax.forEach((q,i)=>ALL_ITEM_IDS.push({id:`${l.id}-q${i}`, kind:"syntax", lectio:l.id, label:q.lemma.slice(0,42)+(q.lemma.length>42?"…":"")}));
});

function getBox(id){
  try{
    const raw = localStorage.getItem("box:"+id);
    return raw ? JSON.parse(raw) : {box:1, due:Date.now()};
  }catch(e){ return {box:1, due:Date.now()}; }
}
function setBox(id, data){
  try{ localStorage.setItem("box:"+id, JSON.stringify(data)); }catch(e){}
}
const INTERVAL_DAYS = {1:0, 2:1, 3:3, 4:7, 5:14};
function rate(id, level){
  let cur = getBox(id);
  let box = cur.box || 1;
  if(level==="got") box = Math.min(5, box+1);
  else if(level==="shaky") box = Math.max(1, box);
  else box = 1;
  const due = Date.now() + INTERVAL_DAYS[box]*86400000;
  setBox(id, {box, due});
}

let activeCat = "όλα";
let currentLectioId = LECTIOS[0].id;
let lectioSub = "translate";
const CATS = ["όλα","κύριες","δευτερεύουσες","ονοματικοί"];

/* ============================ RENDER: PHENOMENA ============================ */
function renderPhenomFilters(){
  const bar = document.getElementById("phenomFilters");
  bar.innerHTML = CATS.map(c=>`<button data-cat="${c}" class="${c===activeCat?'active':''}">${c}</button>`).join("");
  bar.querySelectorAll("button").forEach(b=>b.onclick=()=>{activeCat=b.dataset.cat;renderPhenomFilters();renderPhenomList();});
}
function freqColor(pct){
  if(pct>=60) return "var(--bad)";
  if(pct>=30) return "var(--mid)";
  return "var(--good)";
}
function renderPhenomList(){
  const list = activeCat==="όλα" ? PHENOMENA : PHENOMENA.filter(p=>p.cat===activeCat);
  document.getElementById("phenomList").innerHTML = list.map(p=>`
    <div class="card ${p.color}">
      <h3>${p.title}<span class="tag ${p.color}">${p.cat}</span></h3>
      ${p.freq!==undefined ? `<div class="freqbar-wrap">
        <div class="freqbar-track"><div class="freqbar-fill" style="width:${p.freq}%;background:${freqColor(p.freq)}"></div></div>
        <div class="freqbar-pct" style="color:${freqColor(p.freq)}">${p.freq}%</div>
      </div>` : ""}
      <p>${p.def}</p>
      <p><b style="color:var(--ink)">Πώς το φτιάχνεις:</b> ${p.build}</p>
      <div class="latin-ex">${p.ex}</div>
      <div class="tip">${p.tip}</div>
      <div class="src">Πηγή: ${p.src}</div>
    </div>`).join("");
}

