function lectioBadge(id){
  return LECTIO_HISTORY[id] || {cls:"b-warm", icon:"⚡", label:"Ποτέ στις Παγκύπριες"};
}

/* ============================ RENDER: LECTIO PICKER ============================ */
function renderLectioPicker(){
  const grid = document.getElementById("lectioGrid");
  grid.innerHTML = LECTIOS.map(l=>{
    const b = lectioBadge(l.id);
    return `<button class="lectio-card ${l.id===currentLectioId?'active':''}" data-id="${l.id}">
      <span class="badge ${b.cls}">${b.icon} ${b.label}</span>
      <div class="roman">${l.roman}</div>
      <div class="lname">${l.title.split(":")[1]?.trim()?.slice(0,38)||""}</div>
      <div class="lmeta">${l.sentences.length} προτάσεις · ${l.syntax.length} συντακτικά</div>
    </button>`;
  }).join("");
  grid.querySelectorAll(".lectio-card").forEach(btn=>{
    btn.onclick = ()=>{ currentLectioId = btn.dataset.id; renderLectioPicker(); renderLectioHead(); renderLectio(); };
  });
}
function renderLectioHead(){
  const l = LECTIOS.find(x=>x.id===currentLectioId);
  document.getElementById("lectioHeadTitle").textContent = l.roman;
  document.getElementById("lectioHeadSub").textContent = l.title.split(":")[1]?.trim() || "";
}

function renderLectio(){
  const l = LECTIOS.find(x=>x.id===currentLectioId);
  const body = document.getElementById("lectioBody");
  if(lectioSub==="translate"){
    if(l.sentences.length===0){
      body.innerHTML = `<div class="empty">Δεν εξήχθη μετάφραση για αυτό το lectio ακόμα.</div>`;
      return;
    }
    body.innerHTML = l.sentences.map((s,i)=>`
      <div class="sentbox" data-id="${l.id}-t${i}">
        <div class="latin">${s.lat}</div>
        <div class="reveal"><b style="color:var(--ink)">Επίσημη μετάφραση:</b> ${s.gr}</div>
        <div class="actions"><button class="btn show-btn" data-act="show">Δείξε μετάφραση</button></div>
        <div class="actions rate-row" style="display:none">
          <button class="btn miss" data-r="miss">Το έχασα</button>
          <button class="btn shaky" data-r="shaky">Λίγη σιγουριά</button>
          <button class="btn got" data-r="got">Το ήξερα</button>
        </div>
      </div>`).join("");
  }else{
    if(l.syntax.length===0){
      body.innerHTML = `<div class="empty">Δεν εξήχθη συντακτική ανάλυση για αυτό το lectio ακόμα.</div>`;
      return;
    }
    body.innerHTML = l.syntax.map((q,i)=>`
      <div class="quizcard" data-id="${l.id}-q${i}">
        <div class="q"><span class="latin-piece">${q.lemma}</span> <span class="badge-real">πραγματικό</span></div>
        <div class="reveal"><b style="color:var(--ink)">Ανάλυση:</b> ${q.expl}</div>
        <div class="actions"><button class="btn show-btn" data-act="show">Δείξε ανάλυση</button></div>
        <div class="actions rate-row" style="display:none">
          <button class="btn miss" data-r="miss">Το έχασα</button>
          <button class="btn shaky" data-r="shaky">Λίγη σιγουριά</button>
          <button class="btn got" data-r="got">Το ήξερα</button>
        </div>
      </div>`).join("");
  }
  attachLectioHandlers();
}
function attachLectioHandlers(){
  document.querySelectorAll("#lectioBody .sentbox, #lectioBody .quizcard").forEach(box=>{
    const id = box.dataset.id;
    const reveal = box.querySelector(".reveal");
    const showBtn = box.querySelector('[data-act="show"]');
    const rateRow = box.querySelector(".rate-row");
    showBtn.onclick = ()=>{
      reveal.classList.add("show");
      showBtn.parentElement.style.display="none";
      rateRow.style.display="flex";
    };
    rateRow.querySelectorAll("button").forEach(b=>{
      b.onclick = ()=>{
        rate(id, b.dataset.r);
        b.parentElement.innerHTML = `<div style="font-size:11.5px;color:var(--ink-faint);padding:6px 0">Καταγράφηκε ✓</div>`;
      };
    });
  });
}

